#include<bits/stdc++.h>
using namespace std;
int dp[5050][5050];
int main()
{
    int n,p;
    scanf("%d%d",&n,&p);
    dp[2][2]=1;
    for(int i=3;i<=n;i++)
    {
        for(int j=2;j<=i;j++)
        {
            dp[i][j]=(dp[i][j-1]+dp[i-1][i-j+1])%p;
        }
    }
    int ans=0;
    for(int i=2;i<=n;i++)
    {
        ans+=dp[n][i];
        ans%=p;
    }
    printf("%d",ans*2%p);
    return 0;
}
